    96→                                            std::string const& cname) const;
    97→
    98→  // Resolve the access level for this database. Might fall back to
    99→  // the special '*' entry if the specific database is not found
   100→  auth::Level databaseAuthLevel(std::string const& dbname) const;
   101→
   102→  // Resolve rights for the specified collection. Falls back to the
   103→  // special '*' entry if either the database or collection is not
   104→  // found.
   105→  auth::Level collectionAuthLevel(std::string const& dbname,
   106→                                  std::string_view cname) const;
   107→
   108→  // Content of `userData` fields
